// Auto-generated — oseias (NVI)
// Do NOT edit manually. Re-run scripts/download-bible.mjs to update.

export const OSEIAS_NVI: Record<number, string[]> = {
  1: ["Esta es la palabra del SEÑOR que vino a Oseas hijo de Beerí durante los reinados de Uzías, Jotán, Acaz y Ezequías, reyes de Judá, y durante el reinado de Jeroboán hijo de Joás, rey de Israel.","La primera vez que el SEÑOR habló por medio de Oseas, le dijo: «Ve y toma por esposa una prostituta, y ten con ella hijos de prostitución, porque el país se ha prostituido por completo. ¡Se ha apartado del SEÑOR!»","Oseas fue y tomó por esposa a Gómer, hija de Diblayin, la cual concibió y le dio a luz un hijo.","Entonces el SEÑOR le dijo: «Ponle por nombre Jezrel, porque dentro de poco haré que la casa real de Jehú pague por la masacre en Jezrel. Así pondré fin al dominio del reino de Israel.","Ese día quebraré el arco de Israel en el valle de Jezrel».","Gómer volvió a concebir y dio a luz una niña. Entonces el SEÑOR le dijo a Oseas: «Ponle por nombre: “Indigna de compasión”,[1] porque no volveré a compadecerme del reino de Israel, sino que le negaré el perdón.","En cambio, tendré compasión de la tribu de Judá, y la salvaré; pero no por medio de arco, ni de espada ni de batallas, ni tampoco por medio de caballos y jinetes, sino por medio del SEÑOR su Dios».","Cuando Gómer destetó a la llamada «Indigna de compasión», volvió a concebir y tuvo otro hijo.","Entonces el SEÑOR le dijo a Oseas: «Ponle por nombre: “Pueblo ajeno”,[2] porque ni ustedes son mi pueblo, ni yo soy su Dios.","»Con todo, los israelitas serán tan numerosos como la arena del mar, que no se puede medir ni contar. Y en el mismo lugar donde se les llamó: “Pueblo ajeno”, se les llamará: “Hijos del Dios viviente”.","El pueblo de Judá se reunirá con el pueblo de Israel, y nombrarán un solo jefe y resurgirán en su país, porque grande será el día de Jezrel."],
  2: ["»Llamen a sus hermanos: “Pueblo mío”,[3] y a sus hermanas: “Compadecidas”.[4]","»¡Échenle en cara a su madre que ni ella es mi esposa ni yo su esposo! ¡Que se quite del rostro el maquillaje de prostituta, y de entre los pechos los adornos de ramera!","De lo contrario, la desnudaré por completo; la dejaré como el día en que nació. La pondré como un desierto: ¡la convertiré en tierra seca y la mataré de sed!","No tendré compasión de sus hijos, porque son hijos de prostitución.","Su madre es una prostituta; ¡la que los concibió es una sinvergüenza! Pues dijo: “Quiero ir tras mis amantes, que me dan mi pan y mi agua, mi lana y mi lino, mi aceite y mis bebidas”.","Por eso le cerraré el paso con espinos; la encerraré para que no encuentre el camino.","Con ardor perseguirá a sus amantes, y al no encontrarlos dirá: “Prefiero volver con mi primer esposo, porque antes me iba mejor que ahora”.","Ella no ha querido reconocer que soy yo quien le da el grano, el vino nuevo y el aceite. Yo le he multiplicado la plata y el oro, ¿y qué hizo con ellos? ¡Falsos dioses![5]","»Por eso, llegado el momento le quitaré mi trigo y mi vino nuevo. La dejaré sin la lana y el lino que le di para cubrir su desnudez.","Voy a exhibir su desvergüenza a la vista de sus amantes, y nadie la librará de mi mano.","Pondré fin a todo su jolgorio: sus peregrinaciones, sus lunas nuevas, sus días de reposo, y sus fiestas solemnes.","Devastaré sus vides y sus higueras, que consideraba la paga de sus amantes. Las convertiré en maleza, y los animales del campo acabarán con ellas.","La llamaré a cuentas por los días en que quemaba ofrendas a sus falsos dioses, cuando se adornaba con zarcillos y joyas, y, olvidándose de mí, se iba tras sus amantes —afirma el SEÑOR—.","»Por eso, ahora voy a seducirla: me la llevaré al desierto y le hablaré con ternura.","Allí le devolveré sus viñedos, y convertiré el valle de la Desgracia[6] en el paso de la Esperanza. Allí me corresponderá, como en los días de su juventud, como en el día en que salió de Egipto.","»En aquel día —afirma el SEÑOR—, ya no me llamarás: “mi señor”,[7] sino que me dirás: “esposo mío”.","Te quitaré de los labios el nombre de tus falsos dioses, y nunca más volverás a invocarlos.","Aquel día haré en tu favor un pacto con los animales del campo, con las aves de los cielos y con los reptiles de la tierra. Eliminaré del país arcos, espadas y guerra, para que todos duerman seguros.","Yo te haré mi esposa para siempre, y te daré como dote el derecho y la justicia, el amor y la compasión.","Te daré como dote mi fidelidad, y entonces conocerás al SEÑOR.","»En aquel día yo responderé —afirma el SEÑOR—; yo le responderé al cielo, y el cielo le responderá a la tierra;","la tierra les responderá al cereal, al vino nuevo y al aceite, y estos le responderán a Jezrel.[8]","Yo la sembraré para mí en la tierra; me compadeceré de la “Indigna de compasión”, a “Pueblo ajeno” lo llamaré: “Pueblo mío”;[9] y él me dirá: “Mi Dios”»."],
  3: ["Me habló una vez más el SEÑOR, y me dijo: «Ve y ama a esa mujer adúltera, que es amante de otro. Ámala como ama el SEÑOR a los israelitas, aunque se hayan vuelto a dioses ajenos y se deleiten con las tortas de pasas que les ofrecen».","Compré entonces a esa mujer por quince monedas de plata[10] y una carga y media de cebada,[11]","y le dije: «Vas a vivir conmigo mucho tiempo, pero sin prostituirte. No tendrás relaciones sexuales con ningún otro hombre. ¡Ni yo te voy a tocar!»","Ciertamente los israelitas vivirán mucho tiempo sin rey ni gobernante, sin sacrificio ni altares, ni efod ni ídolos.","Pero después los israelitas buscarán nuevamente al SEÑOR su Dios, y a David su rey. En los últimos días acudirán con temor reverente al SEÑOR y a sus bondades."],
  4: ["Escuchen, israelitas, la palabra del SEÑOR, porque el SEÑOR va a entrar en juicio contra los habitantes del país: «Ya no hay entre mi pueblo fidelidad ni amor, ni conocimiento de Dios.","Cunden, más bien, el perjurio y la mentira. Abundan el robo, el adulterio y el asesinato. ¡Un homicidio sigue a otro!","Por tanto, se resecará la tierra, y desfallecerán todos sus habitantes. ¡Morirán las bestias del campo, las aves del cielo y los peces del mar!","»¡Que nadie acuse ni reprenda a nadie! ¡Tu pueblo parece acusar al sacerdote!","Tropiezas de día y de noche, y los profetas tropiezan contigo; tu madre dejará de existir,","pues por falta de conocimiento mi pueblo ha sido destruido. »Puesto que rechazaste el conocimiento, yo también te rechazo como mi sacerdote. Ya que te olvidaste de la ley de tu Dios, yo también me olvidaré de tus hijos.","Mientras más aumentaban los sacerdotes, más pecaban contra mí; cambiaron a quien es su gloria en algo deshonroso.","El pecado de mi pueblo es su comida; se regodean en su perversidad.","¡De tal pueblo, tal sacerdote![12] ¡Por eso les pediré cuentas de su conducta y les daré la paga de sus acciones!","»Comerán, pero no quedarán satisfechos; se prostituirán, pero no se saciarán;[13] porque han abandonado al SEÑOR para entregarse","a la prostitución y al vino, ¡al mosto que hace perder la razón!","Mi pueblo consulta a su ídolo de madera, y ese pedazo de palo le responde; su tendencia a prostituirse los descarría; se prostituyen en abierto desafío a su Dios.","En la cumbre de montes y colinas queman ofrendas y ofrecen sacrificios, bajo la agradable sombra de robles, álamos y encinas. Por eso se prostituyen sus hijas y cometen adulterio sus nueras.","Pero no las castigaré por sus prostituciones y adulterios, porque sus propios maridos se juntan con prostitutas y celebran banquetes paganos con las sacerdotisas del templo. ¡Es así como acaba por hundirse un pueblo falto de entendimiento!","»Si tú, Israel, te prostituyes, ¡que no resulte culpable Judá! »No vayan a Guilgal ni suban a Bet Avén,[14] ni juren: “¡Por la vida del SEÑOR!”","Israel es tan indómito como una novilla. ¿Cómo podrá el SEÑOR pastorearlos en campo abierto, como a corderos?","Efraín se ha aliado con las imágenes; ¡pues que se quede con ellas!","Cuando ya no tienen licor, se entregan de lleno a la prostitución, ¡y hasta sus gobernantes aman la deshonra!","¡Por eso un torbellino los arrastrará, y quedarán avergonzados por sus sacrificios!"],
  5: ["»¡Oigan esto, sacerdotes! ¡Pon atención, reino de Israel! ¡Escucha, casa real! ¡Contra ustedes es la sentencia! En Mizpa han sido ustedes una trampa; en el monte Tabor, una red tendida;","en Sitín, una fosa abierta.[15] Por eso, yo los disciplinaré a todos.","Yo conozco bien a Efraín; Israel no me es desconocido. Pero ahora Efraín se ha prostituido; e Israel se ha mancillado.","»No les permiten sus malas obras volverse a su Dios; su tendencia a prostituirse les impide conocer al SEÑOR.","La arrogancia de Israel testificará en su contra, Israel y Efraín tropezarán con su maldad, y hasta Judá caerá con ellos.","Con sus ovejas y sus vacas irán en busca del SEÑOR, pero no lo encontrarán porque él se ha apartado de ellos.","Han traicionado al SEÑOR; han dado a luz hijos de otros padres. ¡Ahora la destrucción[16] devorará sus fincas!","»Toquen la corneta en Guibeá, hagan sonar la trompeta en Ramá, lancen el grito de guerra en Bet Avén:[17] “¡Cuídate las espaldas, Benjamín!”","En el día de la reprensión, Efraín quedará desolado. Entre las tribus de Israel doy a conocer lo que les va a pasar.","Las autoridades de Judá se parecen a los que alteran los linderos. ¡Pues derramaré mi enojo sobre ellos como si derramara un torrente de agua!","Efraín está deprimido, aplastado por el juicio, empeñado en seguir a los ídolos.[18]","¡Pues seré para Efraín como polilla, como carcoma para el pueblo de Judá!","»Cuando Efraín vio su enfermedad y Judá reparó en sus llagas, Efraín recurrió a Asiria y pidió la ayuda del gran rey. Pero el rey no podrá sanarlo, ni tampoco curar sus llagas.","Yo seré como un león para Efraín, como un cachorro para Judá. Yo mismo los haré pedazos, y luego me alejaré; yo mismo me llevaré la presa, y no habrá quien me la arrebate.","Volveré luego a mi morada, hasta que reconozcan su culpa. Buscarán ganarse mi favor; angustiados, me buscarán con ansias»."],
  6: ["¡Vengan, volvámonos al SEÑOR! Él nos ha despedazado, pero nos sanará; nos ha herido, pero nos vendará.","Después de dos días nos dará vida; al tercer día nos levantará, y así viviremos en su presencia.","Conozcamos al SEÑOR; vayamos tras su conocimiento. Tan cierto como que sale el sol, él habrá de manifestarse; vendrá a nosotros como la lluvia de invierno, como la lluvia de primavera que riega la tierra.","«¿Qué voy a hacer contigo, Efraín? ¿Qué voy a hacer contigo, Judá? El amor de ustedes es como nube matutina, como rocío que temprano se evapora.","Por eso los hice pedazos por medio de los profetas; los herí con las palabras de mi boca. ¡Mi sentencia los fulminará como un relámpago!","Lo que pido de ustedes es amor y no sacrificios, conocimiento de Dios y no holocaustos.","Son como Adán: han quebrantado el pacto, ¡me han traicionado!","Galaad es una ciudad de malhechores; sus pisadas dejan huellas de sangre.","Una pandilla de sacerdotes está al acecho en el camino a Siquén y, como banda de salteadores, comete toda clase de infamias.","En el reino de Israel he visto algo horrible: Allí se prostituye Efraín y se mancilla Israel.","»¡A ti también, Judá, te espera la cosecha de tu maldad! »Cuando cambie yo la suerte de mi pueblo,"],
  7: ["cuando sane yo a Israel, la perversidad de Efraín y la maldad de Samaria quedarán al descubierto. Porque ellos cometen fraudes; mientras el ladrón se mete en las casas, una banda de salteadores roba en las calles.","No se ponen a pensar que yo tomo en cuenta todas sus maldades. Sus malas acciones los tienen cercados, y las tengo muy presentes.","»Con su maldad deleitan al rey; con sus mentiras, a las autoridades.","Parecen un horno encendido cuyo fuego no hace falta atizar desde que el panadero prepara la harina hasta que la masa fermenta. ¡Todos ellos son adúlteros!","En la fiesta del rey las autoridades se encienden bajo los efectos del vino, y el rey pierde su dignidad codeándose con la plebe.","Como el horno, se les prende el corazón, dispuesto para la intriga. Su ira se adormece por la noche, pero se reaviva por la mañana.","Todos ellos arden como un horno; devoran a sus gobernantes. Caen todos sus reyes, pero ninguno de ellos me invoca.","»Efraín se mezcla con las naciones; parece una torta cocida de un solo lado.","Los extranjeros le minan las fuerzas, pero él ni cuenta se da. Su pelo se ha encanecido, pero él ni cuenta se da.","La arrogancia de Israel testifica en su contra, pero él no se vuelve al SEÑOR su Dios; a pesar de todo esto, no lo busca.","»Efraín es como una paloma torpe y sin entendimiento, que unas veces pide ayuda a Egipto y otras, recurre a Asiria.","Pero, tan pronto como lo hagan, lanzaré mi red sobre ellos; los derribaré como a las aves del cielo, ¡siete veces los castigaré por sus pecados![19]","¡Ay de ellos, que de mí se alejaron! ¡Que sean destruidos por rebelarse contra mí! Yo bien podría redimirlos, pero ellos no me hablan con la verdad.","No me invocan de corazón, sino que se lamentan echados en sus camas. Para obtener grano y vino nuevo se laceran[20] y se ponen en mi contra.","Yo adiestré y fortalecí sus brazos, pero ellos maquinan maldades contra mí.","No se vuelven al Altísimo; son como un arco engañoso. Sus autoridades caerán a filo de espada por sus palabras insolentes, y en la tierra de Egipto se burlarán de ellos."],
  8: ["»¡Da el toque de trompeta! ¡Un águila se cierne sobre la casa del SEÑOR! Han quebrantado mi pacto y se han rebelado contra mi ley,","y ahora vienen a suplicarme: “¡Dios de Israel, te conocemos!”","Pero Israel ha rechazado el bien, así que un enemigo lo perseguirá.","Establecen reyes que yo no apruebo, y escogen autoridades que no conozco. Con su plata y con su oro se hacen imágenes para su propia destrucción.","Samaria, ¡arroja el becerro que tienes por ídolo! Contra ustedes se ha encendido mi ira. ¿Hasta cuándo estarán sin purificarse?","Oye, Israel: Ese becerro no es Dios; es obra de un escultor. Ese becerro de Samaria será hecho pedazos.","»Sembraron vientos y cosecharán tempestades. El tallo no tiene espiga y no producirá harina; si acaso llegara a producirla, se la tragarían los extranjeros.","Pues a Israel se lo han tragado, y hoy es de poca estima entre las naciones.","Los israelitas subieron a Asiria; se apartaron como terco asno salvaje, y Efraín se ha comprado amantes.","Pero, aunque se los compre entre las naciones, de allí volveré a reunirlos; y comenzarán a retorcerse bajo la opresión de un rey poderoso.","»Efraín edificó muchos altares para expiar sus pecados, pero estos se han convertido en altares para pecar.","Yo podría escribirles mi ley muchas veces, pero ellos la verían como algo extraño.","Me han ofrecido sacrificios y ofrendas, y se han comido la carne, pero eso a mí no me agrada. Voy ahora a tomar en cuenta sus perversidades, y castigaré sus pecados; ¡y tendrán que regresar a Egipto!","Israel se olvidó de su Hacedor y se edificó palacios; Judá multiplicó las ciudades amuralladas; pero yo lanzaré sobre sus ciudades y fortalezas un fuego que las consuma»."],
  9: ["No te alegres, Israel; no hagas fiesta como las naciones, porque te has prostituido. ¡Le has sido infiel a tu Dios! Prefieres la paga de prostituta que recibes en todos los trigales.[21]","Ni el trigo ni las uvas podrán alimentarlos; el vino nuevo no tendrá el gusto que esperaban.","No habitarán en la tierra del SEÑOR; Efraín regresará a Egipto y comerá inmundicias en Asiria.","No le ofrecerán al SEÑOR más libaciones de vino, ni le serán gratos sus sacrificios. Se les volverá pan de lágrimas; quienes lo coman quedarán impuros. Tal vez les sirva para matar el hambre, pero no tendrá cabida en la casa del SEÑOR.","¿Qué harán ustedes en los días de fiesta, o en las peregrinaciones en honor del SEÑOR?","Aunque escapen de la destrucción, los recogerá Egipto y los enterrará Menfis. Sus tesoros de plata se llenarán de ortigas, y los espinos invadirán sus carpas.","Han llegado los días del castigo, han llegado los días de la retribución. ¡Que lo sepa Israel! Es tan grande tu maldad, y tan intensa tu hostilidad, que al profeta se le tiene por necio, y al hombre inspirado por loco.","El profeta, junto con Dios, es el centinela de Efraín,[22] pero enfrenta trampas en todos sus caminos, y hostilidad en la casa de su Dios.","Han llegado al colmo de la corrupción, como en los días de Guibeá; ¡pero Dios se acordará de sus perversidades y los castigará por sus pecados!","«Cuando encontré a Israel, fue como hallar uvas en el desierto; cuando vi a sus antepasados, fue como ver higos tiernos en la higuera. Pero ellos se fueron a Baal Peor y se entregaron a la vergüenza; ¡se volvieron tan detestables como el objeto de su amor!","El esplendor de Efraín saldrá volando, como un ave; no habrá más concepción ni embarazo ni nacimiento.","Y aun cuando vean crecer a sus hijos, yo los arrebataré de este mundo. ¡Ay de ellos cuando los abandone!","He visto a Efraín y a Tiro plantados en una pradera.[23] ¡Pero Efraín entregará sus hijos al verdugo!»","Dales, SEÑOR… ¿qué les darás? ¡Dales vientres que aborten y pechos resecos!","«Toda su maldad comenzó en Guilgal; allí comencé a aborrecerlos. Por causa de sus maldades, los expulsaré de mi casa. No volveré a amarlos, pues todas sus autoridades son rebeldes.","Efraín se ha marchitado: su raíz se secó y no produce fruto. Aunque llegue a tener hijos, mataré el precioso fruto de su vientre».","Como no lo obedecieron, mi Dios los rechazará; ¡andarán errantes entre las naciones!"],
  10: ["Israel era una vid frondosa que daba fruto a su antojo. Pero cuanto más aumentaba su fruto, más altares se construía; cuanto más prosperaba su país, más hermosas hacía sus piedras sagradas.","Su corazón es escurridizo, pero tendrá que cargar con su culpa. El SEÑOR destrozará sus altares y devastará sus piedras sagradas.","Tal vez dirán: «No hemos temido al SEÑOR, y por eso no tenemos rey. Pero, aun si lo tuviéramos, ¿qué podría hacer por nosotros?»","Hablan solo por hablar; juran en falso y hacen tratos; ¡por eso florecen los pleitos como la mala yerba en el campo!","Temen los moradores de Samaria por el becerro que adoran en Bet Avén.[24] El pueblo del becerro hará duelo por él, lo mismo que sus sacerdotes idólatras. Harán lamentos por su esplendor, porque se lo llevarán al destierro.","El becerro será llevado a Asiria como tributo para el gran rey. Efraín quedará avergonzado; Israel se avergonzará de sus ídolos.[25]","Samaria y su rey desaparecerán como rama arrastrada por el agua.","Serán destruidos sus santuarios paganos, lugares de pecado de Israel. ¡Cardos y espinos crecerán sobre sus altares! Entonces dirán a las montañas: «¡Cúbrannos!», y a las colinas: «¡Caigan sobre nosotros!»","«Tú, Israel, has venido pecando desde los días de Guibeá, y allí te has mantenido. ¡En Guibeá la guerra tomará por sorpresa a los malvados!","Cuando yo quiera, los castigaré; entonces las naciones se juntarán contra ellos para aprisionarlos por su doble perversión.","Efraín es una novilla adiestrada a la que le gusta trillar, pero yo no quise ponerle el yugo. Pero ahora voy a uncir a Efraín, y Judá tendrá que arar, y Jacob emparejará la tierra».","¡Siembren para ustedes justicia! ¡Cosechen el fruto del amor, y pónganse a labrar el barbecho! ¡Ya es tiempo de buscar al SEÑOR!, hasta que él venga y les envíe lluvias de justicia.","Pero ustedes sembraron maldad, cosecharon crímenes y comieron el fruto de la mentira, porque confiaron en sus carros y en la multitud de sus guerreros.","Un estruendo de guerra se levantará contra su pueblo, y todas sus fortalezas serán devastadas, como devastó Salmán a Bet Arbel en el día de la batalla, cuando las madres fueron destrozadas junto con sus hijos.","Esto es lo que Betel les hizo a ustedes, a causa de su extrema maldad. ¡Pues el rey de Israel será destruido por completo en cuanto amanezca!"],
  11: ["«Desde que Israel era niño, yo lo amé; de Egipto llamé a mi hijo.","Pero cuanto más lo llamaba, más se alejaba de mí.[26] Ofrecía sacrificios a sus falsos dioses[27] y quemaba incienso a las imágenes.","Yo fui quien enseñó a caminar a Efraín; yo fui quien lo tomó de la mano. Pero él no quiso reconocer que era yo quien lo sanaba.","Lo atraje con cuerdas de ternura,[28] lo atraje con lazos de amor. Le quité de la cerviz el yugo, y con ternura me acerqué para alimentarlo.","»No volverán a Egipto, sino que Asiria reinará sobre ellos, porque no quisieron volverse a mí.","En sus ciudades se blandirán espadas, que destrozarán los barrotes de sus puertas y acabarán con sus planes.","Mi pueblo está resuelto a renegar de mi nombre; por eso, aunque me invoquen, no los exaltaré.","»¿Cómo podría yo entregarte, Efraín? ¿Cómo podría abandonarte, Israel? ¡Yo no podría entregarte como entregué a Admá! ¡Yo no podría abandonarte como a Zeboyín! Dentro de mí, el corazón me da vuelcos, y se me conmueven las entrañas.","Pero no daré rienda suelta a mi ira, ni volveré a destruir a Efraín. Porque en medio de ti no está un hombre, sino que estoy yo, el Dios santo, y no atacaré la ciudad».","El SEÑOR rugirá como león, y ellos lo seguirán. Cuando el SEÑOR lance su rugido, sus hijos vendrán temblando de occidente.","«Vendrán desde Egipto, temblando como aves; vendrán desde Asiria, temblando como palomas, y yo los estableceré en sus casas —afirma el SEÑOR—.","»Efraín me ha rodeado de mentiras, y el reino de Israel con fraude; Judá anda errante, lejos de Dios; ¡lejos del Dios santísimo y fiel!"],
  12: ["Efraín se alimenta de viento: todo el día va tras el viento solano, y multiplica la mentira y la violencia. Hace pactos con Asiria, y a Egipto le da aceite como tributo».","El SEÑOR tiene un pleito contra Judá: le hará pagar a Jacob[29] todo lo que ha hecho, le dará lo que merecen sus obras.","Ya en el seno materno suplantó a su hermano, y cuando se hizo hombre luchó con Dios.","Luchó con el ángel, y lo venció; lloró y le rogó que lo favoreciera. Se lo encontró en Betel, y allí habló con él;","¡habló con el SEÑOR Dios Todopoderoso, cuyo nombre es el SEÑOR!","Pero tú debes volverte a tu Dios, practicar el amor y la justicia, y confiar siempre en él.","Canaán[30] usa balanzas fraudulentas, pues le gusta explotar a los demás.","Efraín dice con jactancia: «¡Cómo me he enriquecido! ¡He amasado una gran fortuna! En todas mis ganancias no encontrarán que haya pecado en algo».","«Yo soy el SEÑOR tu Dios desde que estabas en Egipto, y haré que vuelvas a vivir en carpas, como en los días de nuestro encuentro en el desierto.[31]","Yo les hablé a los profetas; les hice tener muchas visiones, y por medio de ellos les hablé en parábolas».","¿Es Galaad malvado? ¡No hay duda de que no vale nada! En Guilgal sacrifica toros; por eso sus altares quedarán reducidos a montones de piedra entre los surcos del campo.","Jacob huyó a un campo de Aram;[32] Israel trabajó cuidando ovejas en pago por su esposa.","Para sacar a Israel de Egipto, y después cuidarlo, el SEÑOR usó a un profeta.","Pero Efraín ha irritado a su Señor; le ha causado un amargo disgusto. Por eso el Señor le hará pagar sus crímenes y le devolverá sus injurias."],
  13: ["Efraín tenía la preeminencia en Israel. Cuando él hablaba, la gente temblaba. Pero le rindió culto a Baal, y por ese pecado murió.","Sin embargo, siguen pecando, pues se fabrican, según su ingenio, imágenes de fundición e ídolos de plata que no son más que obra de artesanos. De ellos se dice: «Ofrecen sacrificios humanos y besan ídolos en forma de becerros».[33]","Por eso serán como nube matutina, como rocío que temprano se evapora, como paja que se lleva el viento, como humo que se escapa por la chimenea.","«Pero yo soy el SEÑOR tu Dios desde que estabas en Egipto. No conocerás[34] a otro Dios fuera de mí, ni a otro Salvador que no sea yo.","Porque yo fui el que te conoció en el desierto, en esa tierra de terrible aridez.","Les di de comer, y quedaron saciados, y una vez satisfechos, se volvieron arrogantes y se olvidaron de mí.","Por eso, yo seré para ellos como un león; los acecharé junto al camino, como un leopardo.","Los atacaré y les desgarraré el pecho como una osa a quien le quitan sus cachorros. ¡Los devoraré como un león! ¡Los despedazaré como fiera del campo!","»Voy a destruirte, Israel, porque estás contra quien te ayuda.","¿Dónde está tu rey, para que te salve en todas tus ciudades? ¿Dónde están los gobernantes, de los que decías: “Dame rey y autoridades”?","En mi ira te di rey, y en mi enojo te lo quité.","La perversidad de Efraín está bien guardada; se ha tomado nota de su pecado.","Llegan los dolores de parto, pero él es una criatura necia: ¡cuando llega la hora del parto, no se acomoda para salir!","»¿Habré de rescatarlos del poder del sepulcro? ¿Los redimiré de la muerte? ¿Dónde están, oh muerte, tus plagas? ¿Dónde está, oh sepulcro, tu destrucción? ¡Vengan, que no les tendré misericordia!»","Aunque Efraín prospere entre sus hermanos, vendrá el viento del SEÑOR, el viento solano que se levanta del desierto, y se agotarán sus fuentes y manantiales. ¡Y arrebatará sus tesoros, todos sus objetos preciosos!","El pueblo de Samaria cargará con su culpa por haberse rebelado contra su Dios. Caerán a filo de espada; ¡a los niños los lanzarán contra el suelo, y a las embarazadas les abrirán el vientre!"],
  14: ["Vuélvete, Israel, al SEÑOR tu Dios. ¡Tu perversidad te ha hecho caer!","Piensa bien lo que le dirás, y vuélvete al SEÑOR con este ruego: «Perdónanos nuestra perversidad, y recíbenos con benevolencia, pues queremos ofrecerte el fruto de nuestros labios.","Asiria no podrá salvarnos; no montaremos caballos de guerra. Nunca más llamaremos “dios nuestro” a cosas hechas por nuestras manos, pues en ti el huérfano halla compasión».","«Yo corregiré su rebeldía y los amaré de pura gracia, porque mi ira contra ellos se ha calmado.","Yo seré para Israel como el rocío, y lo haré florecer como lirio. ¡Hundirá sus raíces como cedro del Líbano!","Sus vástagos crecerán, y tendrán el esplendor del olivo y la fragancia del cedro del Líbano.","Volverán a habitar bajo mi sombra, y crecerán como el trigo. Echarán renuevos, como la vid, y serán tan famosos como el vino del Líbano.","Efraín, ¿yo qué tengo que ver con las imágenes? ¡Soy yo quien te responde y cuida de ti! Soy como un pino siempre verde; tu fruto procede de mí».","El que es sabio entiende estas cosas; el que es inteligente las comprende. Ciertamente son rectos los caminos del SEÑOR: en ellos caminan los justos, mientras que allí tropiezan los rebeldes."],
};
